    {
        "name": "search_documents",
        "description": "Search the knowledge base for documents matching a query. Returns a list of relevant document titles and excerpts. Use this before answering factual questions.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {
                    "type": "string",
                    "description": "The search query"
                },
                "max_results": {
                    "type": "integer",
                    "description": "Maximum number of results to return (1-20)",
                    "default": 5
                }
            },
            "required": ["query"]
        }
    },
    {
        "name": "create_ticket",
        "description": "Create a support ticket in the ticketing system. Use this when the user reports a bug or requests a feature that cannot be resolved immediately.",
        "input_schema": {
            "type": "object",
            "properties": {
                "title": {
                    "type": "string",
                    "description": "Short descriptive title for the ticket (max 100 chars)"
                },
                "description": {
                    "type": "string",
                    "description": "Detailed description of the issue or request"
                },
                "priority": {
