def dispatch_tool(name: str, tool_input: dict) -> str:
    """Route tool calls returned by Claude to the appropriate function."""
    handlers = {
        "search_documents": search_documents,
        "create_ticket":    create_ticket,
        "send_email":       send_email,
    }
    if name not in handlers:
        return f"Unknown tool: {name}"
    return handlers[name](**tool_input)

def run_agent(messages: list[dict]) -> str:
    while True:
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            tools=tools,
            messages=messages
        )
        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b, "text"))

        # append assistant message with tool_use block(s)
        messages.append({"role": "assistant", "content": response.content})

        # execute each tool and append results
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": str(result)
                })

        messages.append({"role": "user", "content": tool_results})

import jsonschema

def validate_tool_input(tool_name: str, tool_input: dict, tools: list[dict]) -> list[str]:
    """Validate tool input against its schema before executing.
    Returns a list of validation error messages (empty = valid)."""
    schema = next(
        (t["input_schema"] for t in tools if t["name"] == tool_name),
        None
    )
    if schema is None:
        return [f"Unknown tool: {tool_name}"]

    try:
        jsonschema.validate(instance=tool_input, schema=schema)
        return []
    except jsonschema.ValidationError as e:
        return [e.message]

def dispatch_tool_safe(name: str, tool_input: dict, tools: list[dict]) -> str:
    """Validate then dispatch, returning an error string instead of raising."""
    errors = validate_tool_input(name, tool_input, tools)
    if errors:
        # Return error as tool_result so Claude can self-correct
        return f"Schema validation failed: {'; '.join(errors)}"
    return dispatch_tool(name, tool_input)

# Usage in the agent loop
for block in response.content:
